import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: { day: string; icon: string; high: number; low: number }[]; // 5-day forecast array
}

function useComponent(props: Props) {
  const [isHovered, setIsHovered] = useState(false);

  const conditionIcon = useMemo(() => {
    const lower = props.condition.toLowerCase();
    if (lower.includes('sun')) return 'sun';
    if (lower.includes('rain')) return 'cloud-rain';
    if (lower.includes('cloud')) return 'cloud';
    return 'sun';
  }, [props.condition]);

  return { isHovered, setIsHovered, conditionIcon };
}

export default function Component(props: Props) {
  const { isHovered, setIsHovered, conditionIcon } = useComponent(props);

  return (
    <Card 
      radius="lg" 
      padding={24} 
      shadow={isHovered ? 'md' : 'sm'}
    >
      <Stack align="center" gap={16}>
        <Heading level={1}>{props.city}</Heading>
        <Stack align="center" gap={4}>
          <Text variant="bodyLarge" size="4xl" weight="bold">{props.temperature}°{props.unit}</Text>
          <Badge variant="primary">{props.condition}</Badge>
        </Stack>

        <div onMouseEnter={() => setIsHovered(true)} onMouseLeave={() => setIsHovered(false)} style={{ width: '100%' }}>
        <Row justify="between" style={{ width: '100%', marginTop: 'var(--ggui-spacing-4)' }}>
          <Stack gap={4} align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
            <Text weight="medium">{props.humidity}%</Text>
          </Stack>
          <Stack gap={4} align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
            <Text weight="medium">{props.windSpeed} km/h</Text>
          </Stack>
        </Row>
        </div>

        <Divider margin={16} />

        <Stack direction="horizontal" justify="between" style={{ width: '100%' }}>
          {props.forecast.map((f, i) => (
            <Stack key={i} align="center" gap={8} style={{ padding: 'var(--ggui-spacing-2)' }}>
              <Text variant="caption" weight="semibold">{f.day}</Text>
              <Icon name={conditionIcon} size={20} />
              <Text variant="bodySmall">{f.high}° / {f.low}°</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: { id: string; title: string; priority: string; assignee: string; column: string; dueDate: string }[];
  columns: { id?: string; name?: string }[];
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks);
  const [newTask, setNewTask] = useState({ title: '', priority: 'medium', column: 'todo', assignee: '??', dueDate: '' });
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  const counts = useMemo(() => {
    const res: Record<string, number> = {};
    props.columns.forEach(c => c.id && (res[c.id] = 0));
    tasks.forEach(t => res[t.column] = (res[t.column] || 0) + 1);
    return res;
  }, [tasks, props.columns]);

  const addTask = (colId: string) => {
    const newT = { ...newTask, id: Math.random().toString(36).substr(2, 9), column: colId };
    setTasks([...tasks, newT]);
    handleTaskUpdate({ action: 'create', task: newT });
    setIsAdding(null);
    setNewTask({ title: '', priority: 'medium', column: 'todo', assignee: '??', dueDate: '' });
  };

  const moveTask = (taskId: string, column: string) => {
    const updated = tasks.map(t => t.id === taskId ? { ...t, column } : t);
    setTasks(updated);
    handleTaskUpdate({ action: 'move', taskId, column });
  };

  const saveEdit = (taskId: string) => {
    const updated = tasks.map(t => t.id === taskId ? { ...t, title: editTitle } : t);
    setTasks(updated);
    handleTaskUpdate({ action: 'edit', taskId, title: editTitle });
    setEditingTaskId(null);
  };

  return { tasks, columns: props.columns, counts, isAdding, setIsAdding, newTask, setNewTask, addTask, moveTask, editingTaskId, setEditingTaskId, editTitle, setEditTitle, saveEdit };
}

export default function Component(props: Props) {
  const { tasks, columns, counts, isAdding, setIsAdding, newTask, setNewTask, addTask, moveTask, editingTaskId, setEditingTaskId, editTitle, setEditTitle, saveEdit } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={1}>Task Board</Heading>
          <Stack direction="horizontal" gap={12}>
            <Badge variant="primary">{tasks.length} Total</Badge>
            <Badge variant="success">{counts['done'] || 0} Done</Badge>
          </Stack>
        </Row>
        <CardGrid columns={3} gap={16}>
          {columns.map(col => (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius={12}>
              <Stack gap={16}>
                <Row justify="between" align="center">
                  <Heading level={3}>{col.name || 'Column'}</Heading>
                  <Badge>{col.id ? counts[col.id] : 0}</Badge>
                </Row>
                <Stack gap={12}>
                  {col.id && tasks.filter(t => t.column === col.id).map(task => (
                    <Card key={task.id} padding={12} radius="md" shadow="sm" onDoubleClick={() => { setEditingTaskId(task.id); setEditTitle(task.title); }}>
                      <Stack gap={8}>
                        {editingTaskId === task.id ? (
                          <Stack gap={4}>
                            <Input value={editTitle} onChange={setEditTitle} />
                            <Button size="xs" onClick={() => saveEdit(task.id)}>Save</Button>
                          </Stack>
                        ) : (
                          <Text variant="label" style={{ cursor: 'pointer' }}>{task.title}</Text>
                        )}
                        <Row justify="between" align="center">
                          <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'primary'}>{task.priority}</Badge>
                          <Avatar name={task.assignee} size={24} />
                        </Row>
                        <Select 
                          size="sm"
                          value={task.column} 
                          onChange={(newCol) => moveTask(task.id, newCol)}
                          options={columns.filter(c => c.id).map(c => ({ value: c.id!, label: `Move to ${c.name || 'Column'}` }))}
                        />
                      </Stack>
                    </Card>
                  ))}
                  {col.id && (isAdding === col.id ? (
                    <Stack gap={8}>
                      <Input label="Title" placeholder="Task title..." value={newTask.title} onChange={(val) => setNewTask({...newTask, title: val})} />
                      <Select
                        label="Priority"
                        value={newTask.priority}
                        onChange={(val) => setNewTask({...newTask, priority: val})}
                        options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]}
                      />
                      <Button variant="primary" onClick={() => addTask(col.id)}>Save Task</Button>
                      <Button variant="ghost" onClick={() => setIsAdding(null)}>Cancel</Button>
                    </Stack>
                  ) : (
                    <Button variant="ghost" onClick={() => setIsAdding(col.id)}>
                      <Icon name="plus" size={16} /> Add Task
                    </Button>
                  ))}
                </Stack>
              </Stack>
            </Box>
          ))}
        </CardGrid>
      </Stack>
    </Container>
  );
}

