import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: { atomicNumber: number; symbol: string; name: string; atomicWeight: number; category: string; row: number; col: number }[]; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const filteredElements = useMemo(() => {
    const query = searchTerm.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name.toLowerCase().includes(query) ||
        el.symbol.toLowerCase().includes(query)
    );
  }, [props.elements, searchTerm]);

  const categories = useMemo(() => Array.from(new Set(props.elements.map((el) => el.category))), [props.elements]);

  const getCategoryColor = useCallback((category: string) => {
    const mapping: Record<string, string> = {
      'Alkali metal': 'var(--ggui-color-primary-200)',
      'Alkaline earth metal': 'var(--ggui-color-container)',
      'Transition metal': 'var(--ggui-color-primary-300)',
      'Post-transition metal': 'var(--ggui-color-info-100)',
      'Metalloid': 'var(--ggui-color-success-100)',
      'Nonmetal': 'var(--ggui-color-warning-100)',
      'Halogen': 'var(--ggui-color-error-100)',
      'Noble gas': 'var(--ggui-color-primary-100)',
      'Lanthanide': 'var(--ggui-color-neutral-200)',
      'Actinide': 'var(--ggui-color-neutral-300)',
    };
    return mapping[category] || 'var(--ggui-color-surfaceVariant)';
  }, []);

  return { searchTerm, setSearchTerm, selectedElement, setSelectedElement, filteredElements, categories, getCategoryColor };
}

export default function Component(props: Props) {
  const { searchTerm, setSearchTerm, selectedElement, setSelectedElement, filteredElements, categories, getCategoryColor } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Row justify="between" align="center">
          <Heading level={1}>Periodic Table</Heading>
          <SearchField value={searchTerm} onChange={setSearchTerm} placeholder="Search elements..." />
        </Row>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1)',
          }}
        >
          {filteredElements.map((el) => (
            <Box
              key={el.atomicNumber}
              style={{
                gridColumn: el.col,
                gridRow: el.row,
              }}
            >
              <button
                type="button"
                onClick={() => setSelectedElement(el)}
                style={{
                  width: '100%',
                  aspectRatio: '1',
                  padding: 0,
                  border: 'none',
                  background: 'none',
                  cursor: 'pointer',
                }}
              >
                <Card
                padding={4}
                radius="sm"
                border={true}
                shadow="sm"
                style={{
                  height: '100%',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  backgroundColor: getCategoryColor(el.category),
                }}
              >
                <Text variant="caption" style={{ alignSelf: 'start' }}>{el.atomicNumber}</Text>
                <Heading level={5}>{el.symbol}</Heading>
              </Card>
              </button>
            </Box>
          ))}
        </Box>

        <Stack direction="horizontal" gap={8} wrap={true}>
          {categories.map(cat => <Tag key={cat} style={{ backgroundColor: getCategoryColor(cat) }}>{cat}</Tag>)}
        </Stack>

        {selectedElement && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Row justify="between">
                <Heading level={3}>{selectedElement.name} ({selectedElement.symbol})</Heading>
                <Button variant="ghost" onClick={() => setSelectedElement(null)}>Close</Button>
              </Row>
              <Stack direction="horizontal" gap={24}>
                <Stack>
                  <Text variant="label">Atomic Number</Text>
                  <Text>{selectedElement.atomicNumber}</Text>
                </Stack>
                <Stack>
                  <Text variant="label">Atomic Weight</Text>
                  <Text>{selectedElement.atomicWeight}</Text>
                </Stack>
                <Stack>
                  <Text variant="label">Category</Text>
                  <Text>{selectedElement.category}</Text>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

