import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id: string; name: string; price: number; currency: string; rating: number; reviewCount: number; stock: number; description: string; specifications: unknown[]; reviews: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const isOutOfStock = props.product.stock === 0;

  const handleQuantityChange = useCallback((delta: number) => {
    setQuantity(prev => Math.min(Math.max(1, prev + delta), props.product.stock));
  }, [props.product.stock]);

  const handleAdd = useCallback(() => {
    handleAddToCart({ productId: props.product.id, quantity });
  }, [handleAddToCart, props.product.id, quantity]);

  return { quantity, activeTab, setActiveTab, handleQuantityChange, handleAdd, isOutOfStock };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={32}>
        <Stack direction="horizontal" gap={32} align="start" wrap={true}>
          <Box background="var(--ggui-color-surfaceVariant)" padding={48} borderRadius="lg" style={{ flex: 1, minWidth: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Heading level={2} color="var(--ggui-color-onSurfaceVariant)">{props.product.name}</Heading>
          </Box>
          <Stack gap={16} style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1}>{props.product.name}</Heading>
            <Heading level={4} color="var(--ggui-color-primary-600)">{props.product.currency}{props.product.price.toFixed(2)}</Heading>
            <Stack direction="horizontal" gap={4} align="center">
              {Array.from({ length: 5 }).map((_, i) => (
                <Icon key={i} name={i < Math.floor(props.product.rating) ? 'check' : 'minus'} size={16} color={i < Math.floor(props.product.rating) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'} />
              ))}
              <Text variant="bodySmall" style={{ marginLeft: '8px' }}>({props.product.reviewCount} reviews)</Text>
            </Stack>
            <Badge variant={state.isOutOfStock ? 'error' : 'success'}>
              {state.isOutOfStock ? 'Out of Stock' : props.product.stock < 5 ? `Low Stock (${props.product.stock} left)` : 'In Stock'}
            </Badge>
            <Stack direction="horizontal" gap={16} align="center">
              <Button variant="outline" onClick={() => state.handleQuantityChange(-1)} disabled={state.quantity <= 1} aria-label="Decrease quantity">
                <Icon name="minus" size={16} />
              </Button>
              <Text role="status" aria-label={`Current quantity: ${state.quantity}`} style={{ minWidth: '24px', textAlign: 'center' }}>{state.quantity}</Text>
              <Button variant="outline" onClick={() => state.handleQuantityChange(1)} disabled={state.quantity >= props.product.stock} aria-label="Increase quantity">
                <Icon name="plus" size={16} />
              </Button>
              <Button variant="primary" onClick={state.handleAdd} disabled={state.isOutOfStock}>Add to Cart</Button>
            </Stack>
          </Stack>
        </Stack>

        <Tabs
          variant="line"
          items={[
            { key: 'description', label: 'Description', content: <Text>{props.product.description}</Text> },
            { key: 'specs', label: 'Specifications', content: (
              <Table 
                columns={[{key: 'key', header: 'Feature'}, {key: 'value', header: 'Details'}]} 
                data={(props.product.specifications as any[]).map((s: any) => ({key: s.key, value: s.value}))}
              />
            )},
            { key: 'reviews', label: 'Reviews', content: (
              <Stack gap={16}>
                {(props.product.reviews as any[]).map((r: any, i: number) => (
                  <Card key={i} padding={16} shadow="none" border={true}>
                    <Text variant="label">{r.author} - {r.rating} stars</Text>
                    <Text>{r.text}</Text>
                    <Text variant="caption">{r.date}</Text>
                  </Card>
                ))}
              </Stack>
            )}
          ]}
          activeKey={state.activeTab}
          onChange={state.setActiveTab}
        />
      </Stack>
    </Container>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [activeStep, setActiveStep] = useState(1);
  const [formData, setFormData] = useState(props.initialProfile || {
    name: '', email: '', avatar: props.avatarOptions?.[0] || '', role: props.roleOptions?.[0] || '', emailNotifications: true, theme: 'light'
  });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const nameError = formData.name.trim() === '' ? 'Name is required' : '';
  const emailError = !validateEmail(formData.email) ? 'Invalid email format' : '';
  const isStep1Valid = !nameError && !emailError;

  const nextStep = () => setActiveStep((s) => Math.min(s + 1, 3));
  const prevStep = () => setActiveStep((s) => Math.max(s - 1, 1));

  return { activeStep, formData, setFormData, isStep1Valid, nameError, emailError, nextStep, prevStep, handleComplete };
}

export default function Component(props: Props) {
  const { activeStep, formData, setFormData, isStep1Valid, nameError, emailError, nextStep, prevStep, handleComplete } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={2}>Onboarding</Heading>
          <Progress value={(activeStep / 3) * 100} />
          <Text variant="bodySmall">Step {activeStep} of 3</Text>
        </Stack>

        <Card padding={24}>
          {activeStep === 1 && (
            <Stack gap={16}>
              <Heading level={4}>Profile Setup</Heading>
              <FormField label="Name" required><Input value={formData.name} onChange={(v) => setFormData({ ...formData, name: v })} /></FormField>
              <FormField label="Email" required><Input value={formData.email} onChange={(v) => setFormData({ ...formData, email: v })} /></FormField>
              <Text variant="label">Select Avatar</Text>
              <Row gap={12}>
                {(props.avatarOptions || []).map(emoji => (
                  <Button key={emoji} variant={formData.avatar === emoji ? 'primary' : 'outline'} onClick={() => setFormData({ ...formData, avatar: emoji })}>{emoji}</Button>
                ))}
              </Row>
            </Stack>
          )}

          {activeStep === 2 && (
            <Stack gap={16}>
              <Heading level={4}>Preferences</Heading>
              <FormField label="Role"><Select value={formData.role} onChange={(v) => setFormData({ ...formData, role: v })} options={(props.roleOptions || []).map(r => ({ value: r, label: r }))} /></FormField>
              <Row justify="between"><Text>Email Notifications</Text><Toggle checked={formData.emailNotifications} onChange={(v) => setFormData({ ...formData, emailNotifications: v })} /></Row>
              <Row justify="between"><Text>Theme Preference</Text><Toggle checked={formData.theme === 'dark'} onChange={(v) => setFormData({ ...formData, theme: v ? 'dark' : 'light' })} /></Row>
            </Stack>
          )}

          {activeStep === 3 && (
            <Stack gap={16}>
              <Heading level={4}>Review & Confirm</Heading>
              <Card>
                <Text variant="bodySmall">Name: {formData.name}</Text>
                <Text variant="bodySmall">Email: {formData.email}</Text>
                <Text variant="bodySmall">Role: {formData.role}</Text>
                <Text variant="bodySmall">Notifications: {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                <Text variant="bodySmall">Theme: {formData.theme}</Text>
              </Card>
            </Stack>
          )}
        </Card>

        <Row justify="between">
          <Button variant="ghost" disabled={activeStep === 1} onClick={prevStep}>Back</Button>
          {activeStep < 3 ? (
            <Button variant="primary" disabled={activeStep === 1 && !isStep1Valid} onClick={nextStep}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => handleComplete(formData)}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
